        .dpad-h {
          height: 40px;
        }
        .dpad-v {
          width: 40px;
        }
        .dpad-up,
        .dpad-down {
          width: 40px;
          height: 40px;
        }
        .dpad-left,
        .dpad-right {
          width: 40px;
          height: 40px;
        }
        .dpad-btn {
          font-size: 15px;
        }
        .ab-wrap {
